syntax.postgresql:
-- Create a function that calculates order total with tax
CREATE FUNCTION calculate_total(subtotal NUMERIC, tax_rate NUMERIC DEFAULT 0.1)
RETURNS NUMERIC
LANGUAGE plpgsql
AS $$
BEGIN
  RETURN subtotal + (subtotal * tax_rate);
END;
$$;

-- Use in a query
SELECT order_id, calculate_total(subtotal) AS total FROM orders;

-- Create a procedure to transfer funds between users
CREATE PROCEDURE transfer_funds(
  sender_id INT,
  receiver_id INT,
  amount NUMERIC
)
LANGUAGE plpgsql
AS $$
BEGIN
  UPDATE accounts SET balance = balance - amount WHERE user_id = sender_id;
  UPDATE accounts SET balance = balance + amount WHERE user_id = receiver_id;
  COMMIT;
END;
$$;

-- Call the procedure
CALL transfer_funds(1, 2, 100.00);

