syntax.postgresql:
-- Create a custom aggregate that concatenates strings with a separator
CREATE FUNCTION concat_agg_sfunc(state TEXT, value TEXT)
RETURNS TEXT
LANGUAGE plpgsql
AS $$
BEGIN
  IF state IS NULL THEN
    RETURN value;
  END IF;
  RETURN state || ', ' || value;
END;
$$;

CREATE AGGREGATE group_concat(TEXT) (
  SFUNC = concat_agg_sfunc,
  STYPE = TEXT
);

-- Usage
SELECT category, group_concat(name) AS product_names
FROM products
GROUP BY category;

-- SQL language (simple, no procedural logic)
CREATE FUNCTION get_user_email(uid INT)
RETURNS VARCHAR
LANGUAGE SQL
AS $$
  SELECT email FROM users WHERE id = uid;
$$;

-- PL/pgSQL language (procedural logic with variables, loops, IF/ELSE)
CREATE FUNCTION get_user_status(uid INT)
RETURNS VARCHAR
LANGUAGE plpgsql
AS $$
DECLARE
  user_status VARCHAR;
BEGIN
  SELECT status INTO user_status FROM users WHERE id = uid;
  IF user_status IS NULL THEN
    RETURN 'unknown';
  END IF;
  RETURN user_status;
END;
$$;

