BEGIN
  DECLARE user_status VARCHAR(20);
  SELECT status INTO user_status FROM users WHERE id = uid;
  IF user_status IS NULL THEN
    RETURN 'unknown';
  END IF;
  RETURN user_status;
END //
DELIMITER ;

